    if (XSS_PATTERN.test(field2)) {
      return failed(this).feedback("xss-reflected-5a-failed-wrong-field").build();
    }

    double totalSale =
        QTY1.intValue() * 69.99
            + QTY2.intValue() * 27.99
            + QTY3.intValue() * 1599.99
            + QTY4.intValue() * 299.99;

