            .build();
      } else {
        return success(this)
            .feedback("xss-reflected-5a-success-alert")
            .output(cart.toString())
            .build();
      }
    } else {
      userSessionData.setValue("xss-reflected1-complete", "false");
      return failed(this).feedback("xss-reflected-5a-failure").output(cart.toString()).build();
    }
  }
